'use client';

import { useTasks } from '@/context/TaskContext';
import { useAuth } from '@/context/AuthContext';
import { Task } from '@/types';
import { Pencil, Trash2, Clock, CheckCircle2, Circle } from 'lucide-react';
import { motion } from 'framer-motion';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

interface TaskCardProps {
  task: Task;
  onEdit: (task: Task) => void;
}

export default function TaskCard({ task, onEdit }: TaskCardProps) {
  const { deleteTask, updateTask } = useTasks();
  const { user } = useAuth();
  const isCreator = user?._id === task.creator;

  const handleStatusChange = async (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newStatus = e.target.value as 'todo' | 'in-progress' | 'done';
    try {
      await updateTask(task._id, { status: newStatus });
    } catch (err: any) {
      // Error handled by context currently, but component can react if needed
    }
  };

  const handleDelete = async () => {
    // Replaced native confirm with a smoother toast confirmation or direct delete for modern feel
    // In a real app we'd use a nice Dialog, but for now we execute directly and show a toast
    try {
      await deleteTask(task._id);
      toast.success('Task deleted');
    } catch (err) {
      toast.error('Failed to delete task');
    }
  };

  const StatusIcon = {
    'todo': Circle,
    'in-progress': Clock,
    'done': CheckCircle2
  }[task.status];

  const statusColors = {
    'todo': 'text-gray-400',
    'in-progress': 'text-blue-500',
    'done': 'text-green-500'
  }[task.status];

  return (
    <motion.div 
      layout
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      exit={{ opacity: 0, scale: 0.95 }}
      whileHover={{ y: -4, transition: { duration: 0.2 } }}
      className="bg-white p-5 rounded-xl shadow-sm hover:shadow-md border border-gray-100 transition-shadow space-y-4 group"
    >
      <div className="flex justify-between items-start gap-4">
        <h3 className="font-semibold text-gray-800 break-words leading-tight">{task.title}</h3>
        {isCreator && (
          <div className="flex space-x-1 text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
              onClick={() => onEdit(task)} 
              className="p-1.5 hover:bg-blue-50 hover:text-blue-600 rounded-md transition-colors"
            >
              <Pencil size={15} />
            </button>
            <button
              onClick={handleDelete}
              className="p-1.5 hover:bg-red-50 hover:text-red-600 rounded-md transition-colors"
            >
              <Trash2 size={15} />
            </button>
          </div>
        )}
      </div>
      
      {task.description && (
        <p className="text-sm text-gray-500 line-clamp-3 leading-relaxed">{task.description}</p>
      )}
      
      <div className="flex items-center justify-between mt-4 bg-gray-50/50 p-2 rounded-lg -mx-2 -mb-2 border border-gray-100/50">
        <div className="flex items-center space-x-2 text-xs">
          <div className="w-6 h-6 bg-gradient-to-br from-indigo-100 to-blue-100 text-blue-700 rounded-full flex items-center justify-center font-bold shadow-sm ring-1 ring-black/5">
            {task.assignedTo ? task.assignedTo.charAt(0).toUpperCase() : '?'}
          </div>
          <span className="font-medium text-gray-600 truncate max-w-[90px]">
            {task.assignedTo || 'Unassigned'}
          </span>
        </div>
        
        <div className="relative flex items-center bg-white rounded-md border border-gray-200 shadow-sm px-1 overflow-hidden focus-within:ring-2 focus-within:ring-blue-500/20">
          <StatusIcon size={14} className={cn("ml-1.5", statusColors)} />
          <select
            value={task.status}
            onChange={handleStatusChange}
            className="bg-transparent border-none text-xs text-gray-600 focus:ring-0 cursor-pointer py-1.5 pl-1.5 pr-6 appearance-none font-medium"
          >
            <option value="todo">To Do</option>
            <option value="in-progress">In Progress</option>
            <option value="done">Done</option>
          </select>
          {/* Custom subtle dropdown arrow */}
          <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-400">
            <svg className="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"/></svg>
          </div>
        </div>
      </div>
    </motion.div>
  );
}
